import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import React, {useState} from 'react';
import Header from './components/Header';
import Card from './components/Card';
import {product} from './data/products';
import './styles/main.css';
import CartModal from './components/Cart';


function App() {
    const [cart, setCart] = useState([]);
    const [isCartOpen, setIsCartOpen] = useState(false);
    const removeFromCart = (productId) => {
        const newCart = cart.filter(item => item.id !== productId);
        setCart(newCart);
    }

    return (
        <Router>
        <div className="App">
            {/* FIX 1: Передаем функцию открытия в Хедер */}
            <Header 
              cartCount={cart.length} 
              onCartClick={() => setIsCartOpen(true)} 
            />

            <Routes>
                <Route path="/" element={
                    <div style={{ textAlign: 'center', padding: '100px' }}>
                        <h1>Добро пожаловать в ONeBoutique</h1>
                        <p>Премиальная одежда для ценителей стиля</p>
                        <a href="/catalog" style={{ color: '#800020', fontWeight: 'bold' }}>Перейти в каталог →</a>
                    </div>
                } />

                <Route path="/catalog" element={
                    <main style={{ padding: '40px', display: 'flex', gap: '20px', flexWrap: 'wrap', justifyContent: 'center' }}>
                    {/* Тут всё ок */}
                    {product.map(item => (
                        <Card key={item.id} product={item} onAdd={(p) => setCart([...cart, p])} />
                    ))}
                    </main>
                } />
            </Routes>

            {isCartOpen && (
                <CartModal 
                    cartItems={cart}
                    // FIX 2: Здесь должно быть false для закрытия
                    onClose={() => setIsCartOpen(false)} 
                />
            )}
        </div>
        </Router>
    );
}

export default App;
